mapper.select:
SELECT 
FROM goods g
LEFT JOIN user u ON g.user_id = u.id
WHERE g.deleted = 0 AND g.status = 'ACTIVE'

    AND (g.title LIKE CONCAT('%', #{dto.keyword}, '%') OR g.description LIKE CONCAT('%', #{dto.keyword}, '%'))


    AND g.category_id = #{dto.categoryId}


    AND g.`condition` = #{dto.condition}


    AND g.price >= #{dto.minPrice}


    AND g.price <= #{dto.maxPrice}


    AND g.campus = #{dto.campus}


    ORDER BY g.price ASC
    ORDER BY g.price DESC
    ORDER BY g.view_count DESC
    ORDER BY g.favorite_count DESC, g.view_count DESC
    ORDER BY g.create_time DESC

SELECT 
FROM goods g
LEFT JOIN user u ON g.user_id = u.id
WHERE g.deleted = 0 AND g.user_id = #{userId}

    AND g.status = #{status}

ORDER BY g.create_time DESC
LIMIT #{offset}, #{size}
